# @cctt_verify {"v":2,"sym":"sympy.matrices.tests.test_sparse.test_copyin","kind":"function","src_hash":"dd87c396933a0e59","in":{"base":"Any"},"out":{"base":"Any","pred":"s[:, 0] == SparseMatrix(Matrix([0, 1, 0])) and s[3] == 1 and s[3:4] == [1] and s[1, 1] == 42 and s[1, 1:] == SparseMatrix([[42, 0]]) and s[1, :] == SparseMatrix([[1, 5, 6]]) and s[1, :] == SparseMatrix([[1, 42, 43]]) and s[:, :1] == SparseMatrix([17, 1, 0]) and s[:, 0] == SparseMatrix([1, 1, 1]) and s[:, 0] == SparseMatrix([1, 1, 1]) and s[:, 0] == SparseMatrix([1, 1, 1])"},"spec":{"lhs":"test_copyin()","rhs":"test_copyin produces the expected output","over":{"base":"Any"},"name":"test_copyin_correct"},"guarantee":"test_copyin produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.matrices.tests.test_sparse.test_copyin_correct","statement":"Path(test_copyin(x), test_copyin produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"c642057da2bfb118"}
def test_copyin():
    s = SparseMatrix(3, 3, {})
    s[1, 0] = 1
    assert s[:, 0] == SparseMatrix(Matrix([0, 1, 0]))
    assert s[3] == 1
    assert s[3: 4] == [1]
    s[1, 1] = 42
    assert s[1, 1] == 42
    assert s[1, 1:] == SparseMatrix([[42, 0]])
    s[1, 1:] = Matrix([[5, 6]])
    assert s[1, :] == SparseMatrix([[1, 5, 6]])
    s[1, 1:] = [[42, 43]]
    assert s[1, :] == SparseMatrix([[1, 42, 43]])
    s[0, 0] = 17
    assert s[:, :1] == SparseMatrix([17, 1, 0])
    s[0, 0] = [1, 1, 1]
    assert s[:, 0] == SparseMatrix([1, 1, 1])
    s[0, 0] = Matrix([1, 1, 1])
    assert s[:, 0] == SparseMatrix([1, 1, 1])
    s[0, 0] = SparseMatrix([1, 1, 1])
    assert s[:, 0] == SparseMatrix([1, 1, 1])


