# @cctt_verify {"v":2,"sym":"sympy.matrices.tests.test_sparse.test_lower_triangular_solve","kind":"function","src_hash":"aeabdf2f67098805","in":{"base":"Any"},"out":{"base":"Any","pred":"A.lower_triangular_solve(B) == sol and A.lower_triangular_solve(C) == sol"},"spec":{"lhs":"test_lower_triangular_solve()","rhs":"test_lower_triangular_solve produces the expected output","over":{"base":"Any"},"name":"test_lower_triangular_solve_correct"},"guarantee":"test_lower_triangular_solve produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.matrices.tests.test_sparse.test_lower_triangular_solve_correct","statement":"Path(test_lower_triangular_solve(x), test_lower_triangular_solve produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"a3271c890823fe7d"}
def test_lower_triangular_solve():
    raises(NonSquareMatrixError, lambda:
        SparseMatrix([[1, 2]]).lower_triangular_solve(Matrix([[1, 2]])))
    raises(ShapeError, lambda:
        SparseMatrix([[1, 2], [0, 4]]).lower_triangular_solve(Matrix([1])))
    raises(ValueError, lambda:
        SparseMatrix([[1, 2], [3, 4]]).lower_triangular_solve(Matrix([[1, 2], [3, 4]])))

    a, b, c, d = symbols('a:d')
    u, v, w, x = symbols('u:x')

    A = SparseMatrix([[a, 0], [c, d]])
    B = MutableSparseMatrix([[u, v], [w, x]])
    C = ImmutableSparseMatrix([[u, v], [w, x]])

    sol = Matrix([[u/a, v/a], [(w - c*u/a)/d, (x - c*v/a)/d]])
    assert A.lower_triangular_solve(B) == sol
    assert A.lower_triangular_solve(C) == sol


